  private readonly BUCKET_NAME = 'support-attachments'
  private inquiriesChannel: RealtimeChannel | null = null
  private inquirySubscribers = new Set<(payload: RealtimePostgresChangesPayload<Record<string, unknown>>) => void>()

  // 이미지 첨부파일 업로드
  async uploadAttachment(file: File): Promise<{ success: boolean; data?: SupportAttachment; error?: string }> {
    try {
      const { data: { user }, error: authError } = await this.supabase.auth.getUser()
      if (authError || !user) return { success: false, error: '로그인이 필요합니다.' }

      // 파일 확장자 추출
      const fileExt = file.name.split('.').pop()?.toLowerCase() || 'jpg'
      const timestamp = Date.now()
      const randomStr = Math.random().toString(36).substring(2, 8)
      const fileName = `support_${timestamp}_${randomStr}.${fileExt}`
      const filePath = `inquiries/${user.id}/${fileName}`

      // Storage에 업로드
      const { error: uploadError } = await this.supabase.storage
        .from(this.BUCKET_NAME)
        .upload(filePath, file, {
          contentType: file.type,
          upsert: false,
        })

      if (uploadError) {
        logger.error('첨부파일 업로드 에러', uploadError)
        throw uploadError
      }

      // Public URL 생성
      const { data: { publicUrl } } = this.supabase.storage
        .from(this.BUCKET_NAME)
        .getPublicUrl(filePath)

      return {
        success: true,
        data: {
          url: publicUrl,
          name: file.name,
          size: file.size,
          path: filePath
        }
      }
    } catch (e) {
      return { success: false, error: e instanceof Error ? e.message : '파일 업로드 실패' }
    }
  }

  // 첨부파일 삭제
  async deleteAttachment(path: string): Promise<{ success: boolean; error?: string }> {
    try {
      const { error } = await this.supabase.storage
        .from(this.BUCKET_NAME)
        .remove([path])

      if (error) throw error
      return { success: true }
    } catch (e) {
      return { success: false, error: e instanceof Error ? e.message : '파일 삭제 실패' }
    }
  }

  // 문의 정렬: 완료되지 않은 문의를 먼저, 그 안에서 최신순
  private sortInquiriesByStatus(inquiries: SupportInquiry[]): SupportInquiry[] {
    return inquiries.sort((a, b) => {
      // 완료 상태: resolved, closed
      const aCompleted = a.status === 'resolved' || a.status === 'closed'
      const bCompleted = b.status === 'resolved' || b.status === 'closed'
      
      // 완료되지 않은 문의를 먼저
      if (aCompleted !== bCompleted) {
        return aCompleted ? 1 : -1
      }
      
      // 같은 그룹 내에서는 최신순 (created_at 내림차순)
      const aDate = new Date(a.created_at || 0).getTime()
      const bDate = new Date(b.created_at || 0).getTime()
      return bDate - aDate
    })
  }

  // 문의 생성
  async createInquiry(payload: CreateSupportInquiryPayload): Promise<{ success: boolean; inquiryId?: number; error?: string }> {
    try {
      const { data: { user }, error: authError } = await this.supabase.auth.getUser()
      if (authError || !user) return { success: false, error: '로그인이 필요합니다.' }

      const { data: employee } = await this.supabase
        .from('employees')
        .select('id, name, email')
        .eq('email', user.email)
        .maybeSingle()

      const { data: created, error } = await this.supabase
        .from('support_inquires')
        .insert({
          user_id: user.id,
          user_email: employee?.email || user.email,
          user_name: employee?.name || '',
          requester_id: employee?.id,
          inquiry_type: payload.inquiry_type,
          subject: payload.subject,
          message: payload.message,
          purchase_request_id: payload.purchase_request_id ?? null,
          purchase_info: payload.purchase_info,
          purchase_order_number: payload.purchase_order_number,
          inquiry_payload: payload.inquiry_payload ?? null,
          status: 'open',
          attachments: payload.attachments || []
        })
        .select('id')
        .single()

      if (error) {
        logger.error('문의 등록 에러', error, {
          code: error.code,
          details: error.details,
          hint: error.hint
        })
        return { success: false, error: error.message }
      }

      const inquiryId = created?.id as number | undefined
      if (!inquiryId) {
        return { success: false, error: '문의 ID를 확인할 수 없습니다.' }
      }

      return { success: true, inquiryId }
    } catch (e) {
      return { success: false, error: e instanceof Error ? e.message : '문의 접수 실패' }
    }
  }

