  subscribeToInquiryMessages(inquiryId: number, callback: (payload: RealtimePostgresChangesPayload<Record<string, unknown>>) => void) {
    return this.supabase
      .channel(`support_inquiry_messages_${inquiryId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'support_inquiry_messages',
          filter: `inquiry_id=eq.${inquiryId}`
        },
        callback
      )
      .subscribe()
  }

  async resolveInquiry(inquiryId: number): Promise<{ success: boolean; error?: string }> {
    try {
      const { data: inquiryMeta } = await this.supabase
        .from('support_inquires')
        .select('inquiry_type,inquiry_payload')
        .eq('id', inquiryId)
        .maybeSingle()
      const meta = inquiryMeta as { inquiry_type?: string; inquiry_payload?: { items?: { item_id?: string }[]; delete_target?: string; statement_id?: string } } | null
      const payloadItems = Array.isArray(meta?.inquiry_payload?.items)
        ? meta.inquiry_payload.items
        : []
      const hasUndefinedItemId = payloadItems.some((item: { item_id?: string }) => {
        const rawItemId = item?.item_id
        return rawItemId === undefined || rawItemId === null || rawItemId === 'undefined' || rawItemId === ''
      })
      const inquiryType = meta?.inquiry_type || null
      const shouldUseFallbackResolve =
        (inquiryType === 'quantity_change' || inquiryType === 'price_change') && hasUndefinedItemId

      if (shouldUseFallbackResolve) {
        const fallbackResult = await this.updateInquiryStatus(inquiryId, 'resolved')
        if (!fallbackResult.success) {
          return { success: false, error: fallbackResult.error || '완료 처리 실패' }
        }
        return { success: true }
      }

      // 거래명세서 삭제 요청인 경우: RPC 호출 전에 image_url 조회 (RPC에서 DB 삭제 후 조회 불가)
      let statementImageUrl: string | null = null
      if (inquiryType === 'delete' && meta?.inquiry_payload?.delete_target === 'statement' && meta?.inquiry_payload?.statement_id) {
        const { data: stmt } = await this.supabase
          .from('transaction_statements')
          .select('image_url')
          .eq('id', meta.inquiry_payload.statement_id)
          .maybeSingle()
        statementImageUrl = (stmt as { image_url?: string } | null)?.image_url || null
      }

      const { error } = await this.supabase.rpc('resolve_inquiry', { p_inquiry_id: inquiryId })
      if (error) throw error

      // 거래명세서 삭제 완료 후 Storage 파일 삭제
      if (statementImageUrl) {
        try {
          const path = statementImageUrl.split('/receipt-images/')[1]
          if (path) {
            await this.supabase.storage.from('receipt-images').remove([path])
          }
        } catch (e) {
          logger.warn('거래명세서 Storage 파일 삭제 실패 (DB 삭제는 완료):', e)
        }
      }

      // 상태 확인(비밀 없음): resolved로 실제 반영됐는지
      await this.supabase
        .from('support_inquires')
        .select('id,status,processed_at,updated_at')
        .eq('id', inquiryId)
        .maybeSingle()

      return { success: true }
    } catch (e) {
      return { success: false, error: e instanceof Error ? e.message : '완료 처리 실패' }
    }
  }

