  // 문의 상태 업데이트 (관리자용)
  async updateInquiryStatus(
    inquiryId: number, 
    status: 'open' | 'in_progress' | 'resolved' | 'closed',
    resolution_note?: string
  ): Promise<{ success: boolean; error?: string }> {
    try {
      const { data: { user }, error: authError } = await this.supabase.auth.getUser()
      if (authError || !user) return { success: false, error: '로그인이 필요합니다.' }

      const { data: employee } = await this.supabase
        .from('employees')
        .select('name')
        .eq('email', user.email)
        .single()

      const updateData: { status: string; handled_by: string; updated_at: string; processed_at?: string; resolution_note?: string } = {
        status,
        handled_by: employee?.name || user.email || '',
        updated_at: new Date().toISOString()
      }

      // resolved나 closed 상태로 변경 시 처리 시간 기록
      if (status === 'resolved' || status === 'closed') {
        updateData.processed_at = new Date().toISOString()
      }

      // resolution_note가 있으면 추가
      if (resolution_note) {
        updateData.resolution_note = resolution_note
      }

      const { error } = await this.supabase
        .from('support_inquires')
        .update(updateData)
        .eq('id', inquiryId)

      if (error) throw error

      return { success: true }
    } catch (e) {
      return { success: false, error: e instanceof Error ? e.message : '상태 업데이트 실패' }
    }
  }


  // 내가 요청한 발주 목록 조회 (수정/삭제 요청용)
  async getMyPurchaseRequests(startDate?: string, endDate?: string, requesterName?: string) {
    try {
      const { data: { user }, error: authError } = await this.supabase.auth.getUser()
      if (authError || !user) return { success: false, data: [], error: '로그인이 필요합니다.' }

      let targetName = requesterName
      if (!targetName) {
        const { data: employee } = await this.supabase
          .from('employees')
          .select('name')
          .eq('email', user.email)
          .single()

        if (!employee) {
          return { success: false, data: [], error: '사용자 정보를 찾을 수 없습니다.' }
        }
        targetName = employee.name
      }

      let query = this.supabase
        .from('purchase_requests')
        .select('id,purchase_order_number,vendor_name,request_date,created_at,requester_name,middle_manager_status,final_manager_status,delivery_request_date,revised_delivery_request_date,purchase_request_items(id,line_number,item_name,specification,quantity,unit_price_value,amount_value)')
        .eq('requester_name', targetName)
        .order('created_at', { ascending: false })

      if (startDate) {
        query = query.gte('created_at', `${startDate}T00:00:00`)
      }
      if (endDate) {
        query = query.lte('created_at', `${endDate}T23:59:59.999`)
      }

      const { data, error } = await query.limit(100)

      if (error) throw error

      return { success: true, data: data || [] }
    } catch (e) {
      return { success: false, data: [], error: e instanceof Error ? e.message : '발주요청 조회 실패' }
    }
  }

